import React from 'react';
import { Link } from 'react-router-dom';
import overviewData from '../data/overview.json';
import predictions from '../data/predictions.json';

const { paper, dataset, groups } = overviewData;

export default function Home() {
    return (
        <div style={{ paddingTop: 56, minHeight: '100vh', background: '#020617' }}>

            {/* ── Hero section ───────────────────────────────────────────── */}
            <div style={{
                background: 'radial-gradient(ellipse 80% 50% at 50% -10%, rgba(239,68,68,0.15), transparent)',
                padding: '80px 20px 60px',
                textAlign: 'center',
                maxWidth: 860,
                margin: '0 auto'
            }}>

                {/* Top badge */}
                <div style={{
                    display: 'inline-block',
                    background: 'rgba(167,139,250,0.12)',
                    border: '1px solid rgba(167,139,250,0.3)',
                    borderRadius: 20,
                    padding: '5px 16px',
                    fontSize: 12,
                    color: '#c4b5fd',
                    marginBottom: 20,
                    fontWeight: 500,
                }}>
                    Final Year Project · {paper.venue}
                </div>

                {/* Title */}
                <h1 style={{
                    fontSize: 'clamp(24px, 5vw, 44px)',
                    fontWeight: 800,
                    lineHeight: 1.2,
                    marginBottom: 16,
                    letterSpacing: -0.5,
                }}>
                    <span style={{
                        background: 'linear-gradient(135deg, #f1f5f9, #94a3b8)',
                        WebkitBackgroundClip: 'text',
                        WebkitTextFillColor: 'transparent',
                    }}>
                        Data-Driven Crime Analysis
                    </span>
                    <br />
                    <span style={{
                        background: 'linear-gradient(135deg, #ef4444, #f97316)',
                        WebkitBackgroundClip: 'text',
                        WebkitTextFillColor: 'transparent',
                    }}>
                        & Prediction Using ML
                    </span>
                </h1>

                {/* Subtitle */}
                <p style={{
                    fontSize: 15,
                    color: '#94a3b8',
                    lineHeight: 1.7,
                    maxWidth: 600,
                    margin: '0 auto 10px',
                }}>
                    {paper.subtitle} · Fairness-aware multi-task deep learning model
                </p>

                {/* Dataset info */}
                <p style={{ fontSize: 13, color: '#475569', marginBottom: 36 }}>
                    NCRB India · 2017–2022 · {dataset.total_records.toLocaleString()} records
                    · {dataset.states} states · {dataset.districts}+ districts
                </p>

                {/* 🔥 KPI SECTION (UPDATED) */}
                <div style={{
                    display: 'inline-flex',
                    background: 'rgba(167,139,250,0.08)',
                    border: '1px solid rgba(167,139,250,0.2)',
                    borderRadius: 12,
                    padding: '14px 24px',
                    marginBottom: 40,
                    flexWrap: 'wrap',
                    justifyContent: 'center',
                    gap: 20,
                }}>
                    <Kpi label="Model" value="FC-MT-LSTM" color="#a78bfa" />
                    <Divider />
                    <Kpi label="MAE" value={predictions.overall.mae.toFixed(2)} color="#f97316" />
                    <Divider />
                    <Kpi label="RMSE" value={predictions.overall.rmse.toFixed(2)} color="#ef4444" />
                    <Divider />
                    <Kpi label="R² Score" value={predictions.overall.r2.toFixed(4)} color="#34d399" />
                    <Divider />
                    <Kpi label="Fairness Ratio" value={predictions.overall.fairness_ratio.toFixed(2)} color="#64B5F6" />
                </div>

                {/* 🔥 Model Info Line */}
                <div style={{ fontSize: 12, color: '#475569', marginBottom: 30 }}>
                    Trained locally · {predictions.training_time_min} min · {predictions.total_predictions.toLocaleString()} predictions
                </div>

                {/* Buttons */}
                <div style={{ display: 'flex', gap: 12, justifyContent: 'center', flexWrap: 'wrap' }}>
                    <Link to="/overview" style={{
                        background: 'linear-gradient(135deg, #ef4444, #f97316)',
                        color: '#fff',
                        borderRadius: 8,
                        padding: '10px 24px',
                        fontSize: 14,
                        fontWeight: 600,
                    }}>
                        Explore the Data →
                    </Link>

                    <Link to="/trends" style={{
                        background: 'transparent',
                        color: '#94a3b8',
                        borderRadius: 8,
                        padding: '10px 24px',
                        fontSize: 14,
                        fontWeight: 500,
                        border: '1px solid rgba(255,255,255,0.08)',
                    }}>
                        View Trends
                    </Link>
                </div>
            </div>

            {/* ── Protected groups ───────────────────────────────────────── */}
            <div style={{ maxWidth: 1100, margin: '0 auto', padding: '0 20px 48px' }}>
                <h2 style={{
                    textAlign: 'center',
                    fontSize: 17,
                    fontWeight: 700,
                    color: '#64748b',
                    marginBottom: 20,
                }}>
                    4 Protected Groups Studied
                </h2>

                <div style={{
                    display: 'grid',
                    gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))',
                    gap: 14,
                }}>
                    {groups.map(g => (
                        <div key={g.name} style={{
                            background: '#111827',
                            border: `1px solid ${g.color}22`,
                            borderLeft: `3px solid ${g.color}`,
                            borderRadius: 12,
                            padding: 18,
                        }}>
                            <div style={{
                                display: 'flex',
                                alignItems: 'center',
                                gap: 8,
                                marginBottom: 8,
                            }}>
                                <div style={{
                                    width: 10,
                                    height: 10,
                                    borderRadius: 2,
                                    background: g.color,
                                }} />
                                <span style={{ fontWeight: 700, color: g.color, fontSize: 15 }}>
                                    {g.name}
                                </span>
                                <span style={{ marginLeft: 'auto', fontSize: 11, color: '#475569' }}>
                                    {g.records.toLocaleString()} records
                                </span>
                            </div>

                            <p style={{ fontSize: 12, color: '#64748b', lineHeight: 1.5 }}>
                                {g.desc}
                            </p>

                            <div style={{ marginTop: 8, fontSize: 11, color: '#475569' }}>
                                {g.categories} crime categories
                            </div>
                        </div>
                    ))}
                </div>
            </div>

            {/* ── Navigation cards ───────────────────────────────────────── */}
            <div style={{ maxWidth: 1100, margin: '0 auto', padding: '0 20px 48px' }}>
                <h2 style={{
                    textAlign: 'center',
                    fontSize: 17,
                    fontWeight: 700,
                    color: '#64748b',
                    marginBottom: 20,
                }}>
                    Explore the Dashboard
                </h2>

                <div style={{
                    display: 'grid',
                    gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))',
                    gap: 14,
                }}>
                    {navCards.map(card => (
                        <Link key={card.to} to={card.to} style={{
                            background: '#111827',
                            border: '1px solid rgba(255,255,255,0.06)',
                            borderRadius: 12,
                            padding: '20px',
                        }}>
                            <div style={{ fontSize: 28, marginBottom: 10 }}>{card.icon}</div>
                            <div style={{ fontWeight: 700, fontSize: 14, color: '#f1f5f9', marginBottom: 4 }}>
                                {card.label}
                            </div>
                            <div style={{ fontSize: 12, color: '#475569' }}>{card.desc}</div>
                        </Link>
                    ))}
                </div>
            </div>

        </div>
    );
}

/* Helpers */
function Kpi({ label, value, color }) {
    return (
        <div style={{ textAlign: 'center' }}>
            <div style={{ fontSize: 20, fontWeight: 800, color }}>{value}</div>
            <div style={{ fontSize: 10, color: '#475569', marginTop: 3 }}>{label}</div>
        </div>
    );
}

function Divider() {
    return (
        <div style={{ width: 1, background: 'rgba(255,255,255,0.08)' }} />
    );
}

const navCards = [
    { to: '/overview', icon: '📊', label: 'Dataset Overview', desc: '21K records · 36 states · 188 features' },
    { to: '/trends', icon: '📈', label: 'Crime Trends', desc: '2017–2022 patterns by group and state' },
    { to: '/cities', icon: '🏙️', label: 'Metro Cities', desc: '34 major cities · 2021–2023 analysis' },
];
